104: func (c *HTTPClientConfig) UnmarshalYAML(unmarshal func(interface{}) error) error {
105: 	type plain HTTPClientConfig
106: 	if err := unmarshal((*plain)(c)); err != nil {
107: 		return err
108: 	}
109: 	return c.Validate()
