388: func newTLSRoundTripper(
389: 	cfg *tls.Config,
390: 	caFile string,
391: 	newRT func(*tls.Config) (http.RoundTripper, error),
392: ) (http.RoundTripper, error) {
393: 	t := &tlsRoundTripper{
394: 		caFile:    caFile,
395: 		newRT:     newRT,
396: 		tlsConfig: cfg,
397: 	}
398: 
399: 	rt, err := t.newRT(t.tlsConfig)
400: 	if err != nil {
401: 		return nil, err
402: 	}
403: 	t.rt = rt
404: 
405: 	_, t.hashCAFile, err = t.getCAWithHash()
406: 	if err != nil {
407: 		return nil, err
408: 	}
409: 
410: 	return t, nil
411: }
