413: func (t *tlsRoundTripper) getCAWithHash() ([]byte, []byte, error) {
414: 	b, err := readCAFile(t.caFile)
415: 	if err != nil {
416: 		return nil, nil, err
417: 	}
418: 	h := md5.Sum(b)
419: 	return b, h[:], nil
420: 
421: }
